1	//! Coroutine library — port of `lcorolib.c`.
2	//!
3	//! Provides the `coroutine.*` standard-library table: `create`, `resume`,
4	//! `running`, `status`, `wrap`, `yield`, `isyieldable`, and `close`.
5	//!
6	//! # Phase A–D stub notice
7	//!
8	//! Every function that requires actual coroutine execution (`resume`, `yield`,
9	//! cross-thread `xmove`, `new_thread`, `close_thread`) is **unimplemented** and
10	//! will panic at runtime.  The argument-checking and result-packaging logic is
11	//! translated faithfully so that Phase E can drop in the real implementations
12	//! without restructuring.  Phase E wires real stackful coroutines via
13	//! `corosensei`.  See PORTING.md §2 #6.
14	//!
15	//! Translated from: `reference/lua-5.4.7/src/lcorolib.c` (210 lines, 12 functions)
16	//! Target crate: `lua-stdlib`
17	
18	// TODO(port): LuaState, GcRef<LuaState>, LuaStatus, and related types live in
19	// lua-vm / lua-types; all unresolved imports will be fixed in Phase B.
20	use lua_types::{
21	    closure::LuaClosure,
22	    error::LuaError,
23	    value::LuaValue,
24	    LuaType,
25	    LuaStatus,
26	    gc::GcRef,
27	};
28	use crate::state_stub::{LuaState, LuaStateStubExt as _, lua_CFunction, upvalue_index, CompareOp, LuaDebug};
29	
30	// ── Coroutine status codes ────────────────────────────────────────────────────
31	
32	// C: #define COS_RUN   0
33	// C: #define COS_DEAD  1
34	// C: #define COS_YIELD 2
35	// C: #define COS_NORM  3
36	
37	/// Coroutine is the currently running thread.
38	const COS_RUN: i32 = 0;
39	
40	/// Coroutine has finished execution or encountered an error.
41	const COS_DEAD: i32 = 1;
42	
43	/// Coroutine is suspended — either yielded or not yet started.
44	const COS_YIELD: i32 = 2;
45	
46	/// Coroutine is normal — it resumed another coroutine and is waiting.
47	const COS_NORM: i32 = 3;
48	
49	/// Human-readable status strings indexed by the `COS_*` constants above.
50	/// Pushed onto the Lua stack as byte strings.
51	///
52	/// C: `static const char *const statname[] = {"running","dead","suspended","normal"};`
53	const STAT_NAMES: [&[u8]; 4] = [b"running", b"dead", b"suspended", b"normal"];
54	
55	// ── Registration table ────────────────────────────────────────────────────────
56	
57	/// Registration table for the `coroutine` standard library.
58	///
59	/// C: `static const luaL_Reg co_funcs[]`
60	///
61	/// Each entry is `(name_bytes, function_pointer)`. Phase B resolves
62	/// `lua_CFunction` to the canonical type alias from `lua-types`.
63	pub const CO_FUNCS: &[(&[u8], lua_CFunction)] = &[
64	    (b"create",      co_create),
65	    (b"resume",      co_resume),
66	    (b"running",     co_running),
67	    (b"status",      co_status),
68	    (b"wrap",        co_wrap),
69	    (b"yield",       co_yield),
70	    (b"isyieldable", co_isyieldable),
71	    (b"close",       co_close),
72	];
73	
74	// ── Internal helpers ──────────────────────────────────────────────────────────
75	
76	/// Retrieves the coroutine thread at stack index 1, raising a type error if
77	/// the argument is absent or not a thread.
78	///
79	/// C: `static lua_State *getco(lua_State *L)`
80	fn get_co(state: &mut LuaState) -> Result<GcRef<lua_types::value::LuaThread>, LuaError> {
81	    let co = state.to_thread(1);
82	    if co.is_none() {
83	        let got = state.arg(1);
84	        return Err(LuaError::type_arg_error(1, "thread", &got));
85	    }
86	    Ok(co.expect("checked above"))
87	}
88	
89	/// Returns one of the `COS_*` status codes describing `co` relative to the
90	/// calling thread `state`. Mirrors `auxstatus` in `lcorolib.c` exactly,
91	/// reading the target coroutine's `status`, call-frame depth, and stack
92	/// top through `GlobalState::threads`.
93	///
94	/// The main thread (id 0) is never stored in the registry, so a value
95	/// pointing at it is always "running" when it is the current thread.
96	/// Phase E-1 cannot resume coroutines, so any registry-resident thread
97	/// is either suspended (initial state, function still on stack) or dead
98	/// (empty stack).
99	///
100	/// C: `static int auxstatus(lua_State *L, lua_State *co)`
101	fn aux_status(state: &mut LuaState, co: &GcRef<lua_types::value::LuaThread>) -> i32 {
102	    let co_id = co.id;
103	    let g = state.global();
104	    if co_id == g.current_thread_id {
105	        return COS_RUN;
106	    }
107	    let entry = match g.threads.get(&co_id) {
108	        Some(e) => e,
109	        None => return COS_DEAD,
110	    };
111	    let co_state: &lua_vm::state::LuaState = &entry.state;
112	    let raw_status = co_state.status;
113	    if raw_status == LuaStatus::Yield as u8 {
114	        return COS_YIELD;
115	    }
116	    if raw_status != LuaStatus::Ok as u8 {
117	        return COS_DEAD;
118	    }
119	    let has_frames = co_state.ci.as_usize() > 0;
120	    if has_frames {
121	        return COS_NORM;
122	    }
123	    let ci_func = co_state.call_info[0].func.0;
124	    let top = co_state.top.0;
125	    let lua_gettop = top as i64 - ci_func as i64 - 1;
126	    if lua_gettop == 0 {
127	        COS_DEAD
128	    } else {
129	        COS_YIELD
130	    }
131	}
132	
133	/// Transfers `narg` arguments from `state` to `co`, resumes the coroutine,
134	/// then transfers results (or error message) back to `state`.
135	///
136	/// Returns the number of result values (≥ 0) on success, or `-1` on error
137	/// with the error object left on top of `state`'s stack.
138	///
139	/// C: `static int auxresume(lua_State *L, lua_State *co, int narg)`
140	fn aux_resume(state: &mut LuaState, _co: GcRef<lua_types::value::LuaThread>, _narg: i32) -> i32 {
141	    // Phase A–D stub: real cross-thread resume needs corosensei runtime
142	    // support (PORTING.md §2 #6 — Phase E).  Emulate C's `auxresume` error
143	    // path: push a string error object onto the caller's stack and return
144	    // -1.  `co_resume` packages this as `(false, msg)` and `aux_wrap`
145	    // re-raises it as a Lua error, matching C-Lua semantics on a coroutine
146	    // that cannot run.  Phase E will replace this body with the full
147	    // checkstack / xmove / lua_resume / xmove sequence.
148	    let msg_bytes: &[u8] = b"not yet implemented: coroutines (Phase E)";
149	    match state.intern_str(msg_bytes) {
150	        Ok(s) => state.push(LuaValue::Str(s)),
151	        Err(_) => state.push(LuaValue::Nil),
152	    }
153	    -1
154	}
155	
156	// ── Public library functions ──────────────────────────────────────────────────
157	
158	/// `coroutine.resume(co [, val1, ...])` — attempt to resume coroutine `co`.
159	///
160	/// On success pushes `true` followed by all values yielded or returned by `co`.
161	/// On failure pushes `false` followed by the error object.
162	///
163	/// C: `static int luaB_coresume(lua_State *L)`
164	pub fn co_resume(state: &mut LuaState) -> Result<usize, LuaError> {
165	    // C: lua_State *co = getco(L);
166	    let co = get_co(state)?;
167	    // C: r = auxresume(L, co, lua_gettop(L) - 1);
168	    // PORT NOTE: lua_gettop returns the argument count; -1 excludes the coroutine
169	    // itself which sits at index 1.
170	    let narg = state.get_top() - 1;
171	    let r = aux_resume(state, co, narg);
172	    if r < 0 {
173	        // C: lua_pushboolean(L, 0); lua_insert(L, -2); return 2;
174	        state.push(LuaValue::Bool(false));
175	        state.insert(-2);
176	        Ok(2)
177	    } else {
178	        // C: lua_pushboolean(L, 1); lua_insert(L, -(r + 1)); return r + 1;
179	        state.push(LuaValue::Bool(true));
180	        state.insert(-(r + 1));
181	        Ok((r + 1) as usize)
182	    }
183	}
184	
185	/// Closure body installed by `coroutine.wrap`. The wrapped function is
186	/// stored in upvalue slot 1.
187	///
188	/// C: `static int luaB_auxwrap(lua_State *L)`
189	///
190	/// Phase A–D emulation: on the first call, runs the entire wrapped function
191	/// with a yield buffer installed, collects all yield batches (one per
192	/// `coroutine.yield(...)` call) and the function's final return values as
193	/// the last batch, stores them in `GlobalState::wrap_iter_state` keyed by
194	/// this closure's identity, and returns the first batch. Subsequent calls
195	/// dispense one batch per call (matching real coroutine semantics) until the
196	/// final-return batch is returned, at which point the entry is removed.
197	/// Phase E replaces this with the full cross-thread `auxresume` sequence
198	/// once stackful coroutines land.
199	fn aux_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
200	    let ci_func = state.current_call_info().func;
201	    let func_val = state.get_at(ci_func);
202	    let cache_key = match &func_val {
203	        LuaValue::Function(LuaClosure::C(ccl)) => ccl.identity(),
204	        _ => {
205	            return Err(LuaError::runtime(format_args!(
206	                "coroutine.wrap: aux_wrap called on non-C-closure"
207	            )))
208	        }
209	    };
210	    drop(func_val);
211	
212	    enum Dispense {
213	        Batch(Vec<LuaValue>),
214	        Drain(Option<LuaError>),
215	    }
216	
217	    let maybe_next: Option<Dispense> = {
218	        let mut g = state.global_mut();
219	        g.wrap_iter_state.get_mut(&cache_key).map(|(batches, idx, pending_err)| {
220	            if *idx < batches.len() {
221	                let batch = batches[*idx].clone();
222	                *idx += 1;
223	                Dispense::Batch(batch)
224	            } else {
225	                Dispense::Drain(pending_err.take())
226	            }
227	        })
228	    };
229	
230	    match maybe_next {
231	        Some(Dispense::Batch(batch)) => {
232	            let n = batch.len();
233	            for v in batch {
234	                state.push(v);
235	            }
236	            return Ok(n);
237	        }
238	        Some(Dispense::Drain(pending_err)) => {
239	            state.global_mut().wrap_iter_state.remove(&cache_key);
240	            if let Some(err) = pending_err {
241	                return Err(err);
242	            }
243	            return Ok(0);
244	        }
245	        None => {}
246	    }
247	
248	    // First call: run the wrapped function with a yield buffer active.
249	    let nargs = state.get_top();
250	    let func = state.value_at(upvalue_index(1));
251	    state.push(func);
252	    if nargs > 0 {
253	        state.insert(1)?;
254	    }
255	    state.push_yield_buffer();
256	    // Use LUA_MULTRET (-1) so the function's final return values reach the stack.
257	    let call_result = state.call(nargs, -1);
258	
259	    // If the call succeeded, capture its final return values as the closing
260	    // batch.  On error we discard whatever residue is on the stack and defer
261	    // the error to fire after all already-buffered yield batches have been
262	    // dispensed (matches C-Lua: yields happen before the error surfaces).
263	    let (mut batches, pending_err) = match call_result {
264	        Ok(_) => {
265	            let nret = state.get_top() as i32;
266	            let final_batch: Vec<LuaValue> =
267	                (1..=nret).map(|i| state.value_at(i)).collect();
268	            let mut batches = state.pop_yield_buffer();
269	            batches.push(final_batch);
270	            (batches, None)
271	        }
272	        Err(e) => {
273	            let batches = state.pop_yield_buffer();
274	            (batches, Some(e))
275	        }
276	    };
277	
278	    // Clear residual stack values; we'll push the first batch instead.
279	    lua_vm::api::set_top(state, 0)?;
280	
281	    if batches.is_empty() {
282	        if let Some(err) = pending_err {
283	            return Err(err);
284	        }
285	        return Ok(0);
286	    }
287	
288	    // Remove and return the first batch; save the rest plus any pending
289	    // error for subsequent calls.
290	    let first = batches.remove(0);
291	    let first_n = first.len();
292	
293	    if !batches.is_empty() || pending_err.is_some() {
294	        state
295	            .global_mut()
296	            .wrap_iter_state
297	            .insert(cache_key, (batches, 0, pending_err));
298	    }
299	
300	    for v in first {
301	        state.push(v);
302	    }
303	    Ok(first_n)
304	}
305	
306	/// `coroutine.create(f)` — create a new coroutine that will run function `f`.
307	///
308	/// Pushes the new thread value and returns 1.
309	///
310	/// Phase E-1: allocates a real `LuaState` registered in
311	/// `GlobalState::threads`, with `f` staged on the new thread's stack so
312	/// `coroutine.status` reports `"suspended"`. The full `xmove` from the
313	/// caller's stack arrives in slice 02b; for this slice the body is
314	/// cloned via `value_at(1)`, which has the same net stack effect since
315	/// `lua_newthread` in C also leaves only the thread value on the
316	/// caller's stack.
317	///
318	/// C: `static int luaB_cocreate(lua_State *L)`
319	pub fn co_create(state: &mut LuaState) -> Result<usize, LuaError> {
320	    state.check_arg_type(1, LuaType::Function)?;
321	    let body = state.value_at(1);
322	    let _nl = state.new_thread(Some(body))?;
323	    Ok(1)
324	}
325	
326	/// `coroutine.wrap(f)` — create a coroutine and return a resuming function.
327	///
328	/// The returned function, when called, resumes the coroutine as if by
329	/// `coroutine.resume`, but raises an error rather than returning `false`.
330	///
331	/// C: `static int luaB_cowrap(lua_State *L)`
332	///
333	/// Phase A–D emulation: captures `f` as upvalue 1 of `aux_wrap`. Each
334	/// call to the returned function forwards directly to `f` with the same
335	/// args. Phase E will replace this with the real `luaB_cocreate` +
336	/// `auxresume` sequence once stackful coroutines land.
337	pub fn co_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
338	    state.check_arg_type(1, LuaType::Function)?;
339	    state.push_value_at(1)?;
340	    state.push_cclosure(aux_wrap, 1)?;
341	    Ok(1)
342	}
343	
344	/// `coroutine.yield([...])` — suspend the running coroutine.
345	///
346	/// All arguments are passed back as results of the corresponding `resume`.
347	///
348	/// C: `static int luaB_yield(lua_State *L)`
349	/// → `return lua_yield(L, lua_gettop(L));`
350	/// → `lua_yield(L,n)` is `lua_yieldk(L, n, 0, NULL)` (lua.h:316)
351	///
352	/// Phase A–D buffering-emulation hook: if `aux_wrap` has installed a yield
353	/// buffer on the LuaState (signalling that a `coroutine.wrap` body is
354	/// running synchronously on the main thread), append the arguments into
355	/// that buffer and return 0 values without suspending. The wrapped
356	/// function continues to run; `aux_wrap` dispenses the buffered values one
357	/// per call. If no buffer is active we fall through to the faithful
358	/// `lua_yieldk` translation, which on the main thread surfaces the C-Lua
359	/// "attempt to yield from outside a coroutine" error.
360	pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
361	    if state.has_yield_buffer() {
362	        let n = state.get_top();
363	        let batch: Vec<LuaValue> = (1..=n).map(|i| state.value_at(i)).collect();
364	        state.yield_buffer_push_batch(batch);
365	        return Ok(0);
366	    }
367	    let n = state.get_top();
368	    let r = lua_vm::do_::lua_yieldk(state, n, 0, None)?;
369	    Ok(r as usize)
370	}
371	
372	/// `coroutine.status(co)` — return a string describing `co`'s current status.
373	///
374	/// Returns one of `"running"`, `"dead"`, `"suspended"`, or `"normal"`.
375	///
376	/// C: `static int luaB_costatus(lua_State *L)`
377	pub fn co_status(state: &mut LuaState) -> Result<usize, LuaError> {
378	    // C: lua_State *co = getco(L);
379	    let co = get_co(state)?;
380	    // C: lua_pushstring(L, statname[auxstatus(L, co)]);
381	    let idx = aux_status(state, &co) as usize;
382	    let name: &[u8] = STAT_NAMES[idx];
383	    let interned = state.intern_str(name)?;
384	    state.push(LuaValue::Str(interned));
385	    Ok(1)
386	}
387	
388	/// `coroutine.isyieldable([co])` — test whether a coroutine (default: current)
389	/// is in a yieldable state.
390	///
391	/// C: `static int luaB_yieldable(lua_State *L)`
392	pub fn co_isyieldable(state: &mut LuaState) -> Result<usize, LuaError> {
393	    let is_yieldable = if matches!(state.type_at(1), LuaType::None) {
394	        state.is_yieldable()
395	    } else {
396	        let co = get_co(state)?;
397	        let co_id = co.id;
398	        let g = state.global();
399	        if co_id == g.main_thread_id {
400	            false
401	        } else {
402	            let entry = g
403	                .threads
404	                .get(&co_id)
405	                .expect("thread value carries an id that must resolve in GlobalState::threads");
406	            entry.state.is_yieldable()
407	        }
408	    };
409	    state.push(LuaValue::Bool(is_yieldable));
410	    Ok(1)
411	}
412	
413	/// `coroutine.running()` — return the current coroutine plus a boolean.
414	///
415	/// The boolean is `true` when the current coroutine is the main thread.
416	///
417	/// C: `static int luaB_corunning(lua_State *L)`
418	pub fn co_running(state: &mut LuaState) -> Result<usize, LuaError> {
419	    // C: int ismain = lua_pushthread(L);
420	    // TODO(port): push_thread pushes a Thread value for the current LuaState and
421	    // returns true iff it is the main thread; Phase B wire-up needed.
422	    let is_main = state.push_thread()?;
423	    // C: lua_pushboolean(L, ismain);
424	    state.push(LuaValue::Bool(is_main));
425	    Ok(2)
426	}
427	
428	/// `coroutine.close(co)` — close a dead or suspended coroutine.
429	///
430	/// Phase E-1 skeleton: the running/normal-rejection branch matches the
431	/// final C-Lua behavior and lands here. Closing a suspended/dead
432	/// coroutine requires running to-be-closed variables and resetting the
433	/// thread; that machinery lands in slice 02d. Until then this returns
434	/// an error rather than silently dropping the work.
435	///
436	/// C: `static int luaB_close(lua_State *L)`
437	pub fn co_close(state: &mut LuaState) -> Result<usize, LuaError> {
438	    let co = get_co(state)?;
439	    let status = aux_status(state, &co);
440	    match status {
441	        COS_RUN | COS_NORM => {
442	            let name = if status == COS_RUN { "running" } else { "normal" };
443	            Err(LuaError::runtime(format_args!(
444	                "cannot close a {} coroutine",
445	                name
446	            )))
447	        }
448	        _ => Err(LuaError::runtime(format_args!(
449	            "coroutine.close not yet implemented for suspended/dead coroutines (Phase E-2d)"
450	        ))),
451	    }
452	}
453	
454	// ── Module entry point ────────────────────────────────────────────────────────
455	
456	/// Opens the `coroutine` standard library by pushing a new table containing
457	/// all `coroutine.*` functions.
458	///
459	/// C: `LUAMOD_API int luaopen_coroutine(lua_State *L)` — `LUAMOD_API` → `pub`.
460	pub fn open_coroutine(state: &mut LuaState) -> Result<usize, LuaError> {
461	    // C: luaL_newlib(L, co_funcs);
462	    // TODO(port): state.new_lib(CO_FUNCS) creates a table from the registration
463	    // slice and leaves it on the stack; Phase B wire-up needed.
464	    state.new_lib(CO_FUNCS)?;
465	    Ok(1)
466	}
467	
468	// ──────────────────────────────────────────────────────────────────────────────
469	// PORT STATUS
470	//   source:        src/lcorolib.c  (210 lines, 12 functions)
471	//   target_crate:  lua-stdlib
472	//   confidence:    medium
473	//   todos:         21
474	//   port_notes:    2
475	//   unsafe_blocks: 0
476	//   notes:         All coroutine execution primitives (resume, yield, xmove,
477	//                  new_thread, close_thread) are Phase E stubs that panic.
478	//                  Argument-checking / result-packaging logic is faithfully
479	//                  translated so Phase E can drop in real implementations.
480	//                  The CO_FUNCS table type references lua_CFunction which is
481	//                  resolved in Phase B.  LuaState / GcRef<LuaState> / LuaStatus
482	//                  imports are all deferred to Phase B.
483	// ──────────────────────────────────────────────────────────────────────────────
